# Multi-Region For Joyboy

## 一、项目结构

```
src/
├── app/                           # App Router
│   ├── [locale]/                 # 动态路由 - 基于语言
│   │   ├── layout.tsx           # 区域相关布局
│   │   └── page.tsx             # 区域首页
│   └── layout.tsx                # 根布局
├── types/                        # 类型定义
│   ├── region.ts                # 区域配置类型
│   └── feature-flags.ts         # 功能开关类型
├── configs/                      # 配置文件
│   ├── regions/                 # 区域配置
│   │   ├── index.ts            # 配置导出
│   │   ├── constants.ts        # 常量定义
│   │   ├── us.ts              # 美国配置
│   │   └── au.ts              # 澳洲配置
│   └── feature-flags/          # 功能开关
│       ├── index.ts           # 开关定义
│       └── constants.ts       # 开关常量
├── hooks/                       # React Hooks
│   ├── useRegion.ts           # 区域 Hook
│   └── useFeatureFlag.ts      # 功能开关 Hook
└── utils/                      # 工具函数
    ├── region.ts              # 区域工具
    └── feature-flags.ts       # 功能开关工具
```

## 二、核心类型定义

### 1. 区域配置类型 (types/region.ts)

```
export interface RegionConfig {
  // 基础信息
  code: string;
  name: string;
  language: string;

  // 格式化配置
  currency: {
    code: string;
    symbol: string;
    position: 'before' | 'after';
  };

  formats: {
    date: string;
    time: string;
    timezone: string;
  };

  // 业务配置
  payment: {
    methods: string[];
    vatRate: number;
  };

  business: {
    customerService: {
      email: string;
      phone: string;
      hours: string;
    };
    socialMedia: Record<string, string>;
  };
}
```

### 2. 功能开关类型 (types/feature-flags.ts)

```
export interface FeatureFlag {
  id: string;
  name: string;
  description?: string;

  isEnabled: boolean;
  enabledRegions?: string[];

  rules?: {
    percentage?: number;
    whitelist?: string[];
    userTypes?: string[];
    startDate?: string;
    endDate?: string;
    conditions?: Record<string, any>;
  };

  dependencies?: string[];

  metrics?: {
    trackingId?: string;
    logSampling?: number;
  };
}
```

